#!/usr/bin/env python3
"""
A CLI to run read-only SQL queries across a folder of CSVs with matching headers.
"""

import argparse
import os
import re
import sys
from typing import Any, Dict, List, Optional, Tuple, Union

import pandas as pd
import sqlparse
from sqlparse.sql import (
    Comparison,
    Function,
    Identifier,
    IdentifierList,
    Parenthesis,
    Token,
    Where,
)
from sqlparse.tokens import Keyword, DML, Punctuation, Wildcard


def load_csv_files(data_dir: str) -> Dict[str, pd.DataFrame]:
    """
    Load all CSV files from the given directory into a dictionary of DataFrames.
    Table names are derived from file paths, with dots replaced by underscores.
    """
    tables = {}
    for root, _, files in os.walk(data_dir):
        for file in files:
            if file.endswith('.csv'):
                file_path = os.path.join(root, file)
                # Calculate relative path from data_dir
                rel_path = os.path.relpath(file_path, data_dir)
                # Remove .csv extension and replace path separators with dots
                table_name = rel_path[:-4].replace(os.sep, '.')
                # Replace dots in filename with underscores
                # The table name format: nested.dir.filename -> if file is "a.b.csv" in dir "nested"
                # it becomes "nested.a_b"
                parts = table_name.split('.')
                if len(parts) > 1:
                    # Replace dots in the filename part (last part) with underscores
                    # Actually, re-reading the spec:
                    # "For nested directories, use `.` to determine which table to query.
                    # If the `.` is in the name of the file, then you need to replace that with `_`."
                    # So we replace dots in the filename only
                    parts[-1] = parts[-1].replace('.', '_')
                    table_name = '.'.join(parts)
                else:
                    # Single file, no directory
                    table_name = table_name.replace('.', '_')

                try:
                    df = pd.read_csv(file_path, dtype=str, keep_default_na=False, na_values=[''])
                    if len(df.columns) == 0:
                        print(f"Warning: {file_path} has no header, skipping.", file=sys.stderr)
                        continue
                    tables[table_name] = df
                except pd.errors.EmptyDataError:
                    print(f"Warning: {file_path} is empty, skipping.", file=sys.stderr)
                    continue

    return tables


class SQLExecutor:
    """Execute SQL queries on a dictionary of DataFrames."""

    def __init__(self, tables: Dict[str, pd.DataFrame]):
        self.tables = tables
        self.alias_map: Dict[str, str] = {}  # alias -> table_name

    def execute(self, query: str) -> pd.DataFrame:
        """Execute a SQL query and return the result as a DataFrame."""
        parsed = sqlparse.parse(query.strip().rstrip(';'))[0]

        # Find the SELECT statement
        tokens = [t for t in parsed.tokens if not t.is_whitespace]

        # Parse the query
        result = self._parse_select(tokens)
        return result

    def _parse_select(self, tokens: List) -> pd.DataFrame:
        """Parse and execute a SELECT statement."""
        idx = 0

        # Expect SELECT keyword
        if not self._is_keyword(tokens[idx], 'SELECT'):
            raise ValueError("Query must start with SELECT")
        idx += 1

        # Parse DISTINCT if present
        distinct = False
        if self._is_keyword(tokens[idx], 'DISTINCT'):
            distinct = True
            idx += 1

        # Parse select list
        select_items, idx = self._parse_select_list(tokens, idx)

        # Parse FROM clause
        if idx >= len(tokens) or not self._is_keyword(tokens[idx], 'FROM'):
            raise ValueError("Missing FROM clause")
        idx += 1

        # Parse table reference
        main_table, main_alias, idx = self._parse_table_ref(tokens, idx)
        if main_alias:
            self.alias_map[main_alias] = main_table
        else:
            self.alias_map[main_table] = main_table

        # Start with the main table
        result = self.tables[main_table].copy()

        # Parse JOIN clauses
        while idx < len(tokens):
            if self._is_keyword(tokens[idx], 'INNER') or self._is_keyword(tokens[idx], 'LEFT') or \
               self._is_keyword(tokens[idx], 'RIGHT') or self._is_keyword(tokens[idx], 'FULL') or \
               self._is_keyword(tokens[idx], 'JOIN'):
                result, idx = self._parse_join(tokens, idx, result)
            else:
                break

        # Parse WHERE clause
        where_expr = None
        if idx < len(tokens) and isinstance(tokens[idx], Where):
            where_expr = tokens[idx]
            idx += 1

        # Parse GROUP BY clause
        group_by_cols = []
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'GROUP'):
            group_by_cols, idx = self._parse_group_by(tokens, idx)

        # Parse HAVING clause
        having_expr = None
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'HAVING'):
            idx += 1  # Skip HAVING keyword
            having_expr = tokens[idx]
            idx += 1

        # Parse ORDER BY clause
        order_by = []
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'ORDER'):
            order_by, idx = self._parse_order_by(tokens, idx)

        # Parse LIMIT clause
        limit = None
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'LIMIT'):
            idx += 1
            limit = int(tokens[idx].value)
            idx += 1

        # Parse OFFSET clause
        offset = None
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'OFFSET'):
            idx += 1
            offset = int(tokens[idx].value)
            idx += 1

        # Execute WHERE
        if where_expr:
            result = self._apply_where(result, where_expr)

        # Execute GROUP BY
        if group_by_cols:
            result = self._apply_group_by(result, select_items, group_by_cols, having_expr)
        else:
            # Check if we have aggregates without GROUP BY
            has_agg = any(self._has_aggregate(item) for item in select_items)
            if has_agg:
                result = self._apply_group_by(result, select_items, [], having_expr)
            else:
                # Just project columns
                result = self._project(result, select_items)

        # Apply DISTINCT
        if distinct:
            result = result.drop_duplicates()

        # Execute ORDER BY
        if order_by:
            result = self._apply_order_by(result, order_by)

        # Execute OFFSET and LIMIT
        if offset:
            result = result.iloc[offset:]
        if limit:
            result = result.head(limit)

        return result

    def _is_keyword(self, token: Token, keyword: str) -> bool:
        """Check if token is a specific keyword."""
        return token.ttype is Keyword and token.value.upper() == keyword.upper()

    def _parse_select_list(self, tokens: List, idx: int) -> Tuple[List, int]:
        """Parse the SELECT list and return list of (column, alias) tuples."""
        select_items = []

        if isinstance(tokens[idx], IdentifierList):
            for item in tokens[idx].get_identifiers():
                select_items.append(self._parse_select_item(item))
            idx += 1
        else:
            select_items.append(self._parse_select_item(tokens[idx]))
            idx += 1

        return select_items, idx

    def _parse_select_item(self, item) -> Tuple:
        """Parse a single SELECT item (column or aggregate function with optional alias)."""
        if isinstance(item, Function):
            # Aggregate function
            func_name = item.get_name().upper()
            args = []
            for arg in item.get_parameters():
                if isinstance(arg, Identifier):
                    args.append(self._resolve_column_ref(arg.value))
                elif arg.ttype is Wildcard:
                    args.append('*')
                else:
                    args.append(arg.value)
            # Check for alias
            alias = self._get_alias(item)
            if not alias:
                alias = f"{func_name}({','.join(str(a) for a in args)})"
            return ('aggregate', func_name, args, alias)
        elif isinstance(item, Identifier):
            # Could be column with alias or just column
            col_ref = self._resolve_column_ref(item.get_real_name())
            alias = item.get_alias() or col_ref.split('.')[-1]
            return ('column', col_ref, alias)
        elif hasattr(item, 'ttype') and item.ttype is Wildcard:
            return ('wildcard', '*', '*')
        else:
            # Simple identifier or expression
            return ('column', item.value, item.value)

    def _get_alias(self, item) -> Optional[str]:
        """Get alias from an identifier or function."""
        if hasattr(item, 'get_alias') and item.get_alias():
            return item.get_alias()
        if hasattr(item, 'get_name'):
            return None
        return None

    def _resolve_column_ref(self, col_ref: str) -> str:
        """Resolve column reference, handling table aliases."""
        if '.' in col_ref:
            parts = col_ref.split('.', 1)
            prefix = parts[0]
            if prefix in self.alias_map:
                return f"{self.alias_map[prefix]}.{parts[1]}"
        return col_ref

    def _parse_table_ref(self, tokens: List, idx: int) -> Tuple[str, Optional[str], int]:
        """Parse a table reference with optional alias."""
        table_name = tokens[idx].value
        idx += 1

        alias = None
        if idx < len(tokens) and self._is_keyword(tokens[idx], 'AS'):
            idx += 1
            alias = tokens[idx].value
            idx += 1
        elif idx < len(tokens) and isinstance(tokens[idx], Identifier) and \
             not self._is_keyword(tokens[idx], 'JOIN') and \
             not self._is_keyword(tokens[idx], 'INNER') and \
             not self._is_keyword(tokens[idx], 'LEFT') and \
             not self._is_keyword(tokens[idx], 'RIGHT') and \
             not self._is_keyword(tokens[idx], 'FULL') and \
             not self._is_keyword(tokens[idx], 'ON') and \
             not self._is_keyword(tokens[idx], 'WHERE') and \
             not self._is_keyword(tokens[idx], 'GROUP') and \
             not self._is_keyword(tokens[idx], 'ORDER') and \
             not self._is_keyword(tokens[idx], 'LIMIT') and \
             not self._is_keyword(tokens[idx], 'OFFSET') and \
             not self._is_keyword(tokens[idx], 'HAVING'):
            # Could be alias without AS
            if tokens[idx].ttype is Keyword:
                pass
            else:
                alias = tokens[idx].value
                idx += 1

        return table_name, alias, idx

    def _parse_join(self, tokens: List, idx: int, left_df: pd.DataFrame) -> Tuple[pd.DataFrame, int]:
        """Parse a JOIN clause and return the joined DataFrame."""
        join_type = 'INNER'
        if self._is_keyword(tokens[idx], 'INNER'):
            join_type = 'INNER'
            idx += 1
        elif self._is_keyword(tokens[idx], 'LEFT'):
            join_type = 'LEFT'
            idx += 1
        elif self._is_keyword(tokens[idx], 'RIGHT'):
            join_type = 'RIGHT'
            idx += 1
        elif self._is_keyword(tokens[idx], 'FULL'):
            join_type = 'FULL'
            idx += 1

        if self._is_keyword(tokens[idx], 'JOIN'):
            idx += 1

        # Parse right table
        right_table, right_alias, idx = self._parse_table_ref(tokens, idx)
        if right_alias:
            self.alias_map[right_alias] = right_table
        else:
            self.alias_map[right_table] = right_table

        right_df = self.tables[right_table].copy()

        # Parse ON clause
        if self._is_keyword(tokens[idx], 'ON'):
            idx += 1

        # Parse join condition (equality predicate)
        left_col, right_col, idx = self._parse_equality_predicate(tokens, idx)

        # Perform the join
        left_df, right_df = self._prefix_columns(left_df, right_df, left_col, right_col)

        how_map = {
            'INNER': 'inner',
            'LEFT': 'left',
            'RIGHT': 'right',
            'FULL': 'outer'
        }

        result = pd.merge(
            left_df,
            right_df,
            left_on=left_col,
            right_on=right_col,
            how=how_map[join_type],
            suffixes=('', '_right')
        )

        return result, idx

    def _prefix_columns(self, left_df: pd.DataFrame, right_df: pd.DataFrame,
                        left_col: str, right_col: str) -> Tuple[pd.DataFrame, pd.DataFrame]:
        """Add prefixes to columns to avoid conflicts."""
        # Find which tables these columns belong to
        left_table = left_col.split('.')[0] if '.' in left_col else None
        right_table = right_col.split('.')[0] if '.' in right_col else None

        # Rename columns to include table prefix
        left_rename = {}
        for col in left_df.columns:
            if '.' not in col:
                new_col = f"{left_table}.{col}" if left_table else col
                left_rename[col] = new_col
        if left_rename:
            left_df = left_df.rename(columns=left_rename)

        right_rename = {}
        for col in right_df.columns:
            if '.' not in col:
                new_col = f"{right_table}.{col}" if right_table else col
                right_rename[col] = new_col
        if right_rename:
            right_df = right_df.rename(columns=right_rename)

        return left_df, right_df

    def _parse_equality_predicate(self, tokens: List, idx: int) -> Tuple[str, str, int]:
        """Parse an equality predicate (col1 = col2)."""
        left_col = tokens[idx].value
        idx += 1

        # Skip '='
        if tokens[idx].ttype is Punctuation or tokens[idx].value == '=':
            idx += 1

        right_col = tokens[idx].value
        idx += 1

        left_col = self._resolve_column_ref(left_col)
        right_col = self._resolve_column_ref(right_col)

        return left_col, right_col, idx

    def _parse_group_by(self, tokens: List, idx: int) -> Tuple[List[str], int]:
        """Parse GROUP BY clause."""
        idx += 1  # Skip GROUP
        if self._is_keyword(tokens[idx], 'BY'):
            idx += 1

        group_cols = []
        while idx < len(tokens):
            if self._is_keyword(tokens[idx], 'HAVING') or \
               self._is_keyword(tokens[idx], 'ORDER') or \
               self._is_keyword(tokens[idx], 'LIMIT') or \
               self._is_keyword(tokens[idx], 'OFFSET'):
                break

            if isinstance(tokens[idx], IdentifierList):
                for ident in tokens[idx].get_identifiers():
                    col = self._resolve_column_ref(ident.value)
                    group_cols.append(col)
                idx += 1
            elif tokens[idx].ttype is Punctuation:
                idx += 1
            else:
                col = self._resolve_column_ref(tokens[idx].value)
                group_cols.append(col)
                idx += 1

        return group_cols, idx

    def _parse_order_by(self, tokens: List, idx: int) -> Tuple[List[Tuple[str, str]], int]:
        """Parse ORDER BY clause and return list of (column, direction) tuples."""
        idx += 1  # Skip ORDER
        if self._is_keyword(tokens[idx], 'BY'):
            idx += 1

        order_items = []
        while idx < len(tokens):
            if self._is_keyword(tokens[idx], 'LIMIT') or \
               self._is_keyword(tokens[idx], 'OFFSET'):
                break

            if tokens[idx].ttype is Punctuation:
                idx += 1
                continue

            col = self._resolve_column_ref(tokens[idx].value)
            idx += 1

            direction = 'ASC'
            if idx < len(tokens) and (self._is_keyword(tokens[idx], 'ASC') or
                                       self._is_keyword(tokens[idx], 'DESC')):
                direction = tokens[idx].value.upper()
                idx += 1

            order_items.append((col, direction))

        return order_items, idx

    def _apply_where(self, df: pd.DataFrame, where_expr: Where) -> pd.DataFrame:
        """Apply WHERE filter to DataFrame."""
        mask = self._evaluate_boolean_expr(df, where_expr)
        return df[mask].reset_index(drop=True)

    def _evaluate_boolean_expr(self, df: pd.DataFrame, expr) -> pd.Series:
        """Evaluate a boolean expression and return a mask Series."""
        tokens = [t for t in expr.tokens if not t.is_whitespace]

        if isinstance(expr, Parenthesis):
            return self._evaluate_boolean_expr(df, expr)

        # Handle AND/OR
        result = None
        operator = None

        i = 0
        while i < len(tokens):
            token = tokens[i]

            if self._is_keyword(token, 'AND') or self._is_keyword(token, 'OR'):
                operator = token.value.upper()
                i += 1
                continue

            if self._is_keyword(token, 'NOT'):
                i += 1
                operand = self._evaluate_boolean_expr(df, tokens[i])
                value = ~operand
                i += 1
            elif isinstance(token, Parenthesis):
                value = self._evaluate_boolean_expr(df, token)
                i += 1
            elif isinstance(token, Comparison):
                value = self._evaluate_comparison(df, token)
                i += 1
            elif isinstance(token, Where):
                value = self._evaluate_boolean_expr(df, token)
                i += 1
            else:
                i += 1
                continue

            if result is None:
                result = value
            elif operator == 'AND':
                result = result & value
            elif operator == 'OR':
                result = result | value

        return result

    def _evaluate_comparison(self, df: pd.DataFrame, comp: Comparison) -> pd.Series:
        """Evaluate a comparison expression."""
        left = comp.left
        right = comp.right

        # Get operator
        op = None
        for token in comp.tokens:
            if token.ttype is sqlparse.tokens.Comparison:
                op = token.value
                break

        left_val = self._get_operand_value(df, left)
        right_val = self._get_operand_value(df, right)

        # Handle LIKE operator
        if isinstance(right, Identifier) or (hasattr(right, 'ttype') and right.ttype is sqlparse.tokens.String.Symbol):
            right_str = right.value if not isinstance(right, Identifier) else right.get_name()
            if self._is_keyword(comp.tokens[1], 'LIKE') or (hasattr(comp.tokens[1], 'value') and comp.tokens[1].value.upper() == 'LIKE'):
                return self._evaluate_like(df, left_val, right_str)

        if op == '=':
            return left_val == right_val
        elif op == '!=':
            return left_val != right_val
        elif op == '<':
            return self._compare_values(left_val, right_val, '<')
        elif op == '<=':
            return self._compare_values(left_val, right_val, '<=')
        elif op == '>':
            return self._compare_values(left_val, right_val, '>')
        elif op == '>=':
            return self._compare_values(left_val, right_val, '>=')

        return pd.Series([True] * len(df))

    def _get_operand_value(self, df: pd.DataFrame, operand) -> Any:
        """Get the value of an operand (column ref, literal, or aggregate)."""
        if isinstance(operand, Function):
            # This shouldn't happen in WHERE, only in HAVING
            return self._compute_aggregate(df, operand)
        elif isinstance(operand, Identifier):
            col_ref = self._resolve_column_ref(operand.value)
            if '.' in col_ref:
                return df[col_ref]
            else:
                # Find the column in the DataFrame
                for col in df.columns:
                    if col == col_ref or col.endswith(f'.{col_ref}'):
                        return df[col]
                return df[col_ref]
        elif operand.ttype is sqlparse.tokens.String.Symbol:
            # String literal
            return operand.value.strip("'\"")
        elif operand.ttype in (sqlparse.tokens.Number.Integer, sqlparse.tokens.Number.Float):
            return float(operand.value)
        else:
            return operand.value

    def _compare_values(self, left: pd.Series, right: Any, op: str) -> pd.Series:
        """Compare values, handling numeric conversion."""
        try:
            left_num = pd.to_numeric(left, errors='coerce')
            right_num = float(right) if not isinstance(right, pd.Series) else pd.to_numeric(right, errors='coerce')

            if op == '<':
                return left_num < right_num
            elif op == '<=':
                return left_num <= right_num
            elif op == '>':
                return left_num > right_num
            elif op == '>=':
                return left_num >= right_num
        except (ValueError, TypeError):
            # Fall back to string comparison
            if op == '<':
                return left < str(right)
            elif op == '<=':
                return left <= str(right)
            elif op == '>':
                return left > str(right)
            elif op == '>=':
                return left >= str(right)

    def _evaluate_like(self, df: pd.DataFrame, col: pd.Series, pattern: str) -> pd.Series:
        """Evaluate LIKE pattern matching."""
        # Convert SQL LIKE pattern to regex
        pattern = pattern.strip("'\"")
        regex_pattern = '^' + pattern.replace('%', '.*').replace('_', '.') + '$'
        return col.astype(str).str.match(regex_pattern, case=True, na=False)

    def _has_aggregate(self, item: Tuple) -> bool:
        """Check if a SELECT item contains an aggregate function."""
        return item[0] == 'aggregate'

    def _apply_group_by(self, df: pd.DataFrame, select_items: List,
                        group_cols: List[str], having_expr: Any = None) -> pd.DataFrame:
        """Apply GROUP BY and compute aggregates."""
        result_data = {}
        column_order = []

        # Determine columns to select
        for item in select_items:
            if item[0] == 'wildcard':
                # For wildcard, select all non-grouped columns
                for col in df.columns:
                    if col not in result_data:
                        result_data[col] = []
                        column_order.append(col)
            elif item[0] == 'column':
                col_ref = item[1]
                alias = item[2]
                result_data[alias] = []
                column_order.append(alias)
            elif item[0] == 'aggregate':
                _, func_name, args, alias = item
                result_data[alias] = []
                column_order.append(alias)

        # Group the data
        if group_cols:
            # Resolve group columns
            resolved_group_cols = []
            for col in group_cols:
                if '.' not in col and col not in df.columns:
                    # Find matching column
                    for c in df.columns:
                        if c == col or c.endswith(f'.{col}'):
                            resolved_group_cols.append(c)
                            break
                else:
                    resolved_group_cols.append(col)

            grouped = df.groupby(resolved_group_cols, dropna=False)
        else:
            # No GROUP BY - aggregate entire DataFrame
            grouped = [(None, df)]

        # Compute aggregates for each group
        group_values_for_having = []

        for group_key, group_df in (grouped if group_cols else [(None, df)]):
            row_data = {}

            for item in select_items:
                if item[0] == 'wildcard':
                    for col in df.columns:
                        if col not in row_data:
                            if group_cols and col in resolved_group_cols:
                                row_data[col] = group_df[col].iloc[0] if len(group_df) > 0 else None
                            else:
                                row_data[col] = group_df[col].iloc[0] if len(group_df) > 0 else None
                elif item[0] == 'column':
                    col_ref = item[1]
                    alias = item[2]
                    resolved_col = self._find_column(df, col_ref)
                    if group_cols and resolved_col in resolved_group_cols:
                        row_data[alias] = group_df[resolved_col].iloc[0] if len(group_df) > 0 else None
                    else:
                        row_data[alias] = group_df[resolved_col].iloc[0] if len(group_df) > 0 else None
                elif item[0] == 'aggregate':
                    _, func_name, args, alias = item
                    value = self._compute_aggregate_for_group(group_df, func_name, args)
                    row_data[alias] = value

            # Store group key for HAVING evaluation
            if having_expr is not None:
                group_values_for_having.append((row_data, group_df))

            # Add row to result
            for key, value in row_data.items():
                result_data[key].append(value)

        result_df = pd.DataFrame(result_data)
        result_df = result_df[column_order]

        # Apply HAVING
        if having_expr is not None:
            # Rebuild with HAVING filter
            filtered_data = {col: [] for col in column_order}

            for row_data, _ in group_values_for_having:
                if self._evaluate_having(row_data, having_expr):
                    for col in column_order:
                        filtered_data[col].append(row_data[col])

            result_df = pd.DataFrame(filtered_data)

        return result_df

    def _find_column(self, df: pd.DataFrame, col_ref: str) -> str:
        """Find the actual column name in the DataFrame."""
        if col_ref in df.columns:
            return col_ref
        # Try to find with table prefix
        for col in df.columns:
            if col == col_ref or col.endswith(f'.{col_ref}'):
                return col
        return col_ref

    def _compute_aggregate_for_group(self, df: pd.DataFrame, func_name: str, args: List) -> Any:
        """Compute an aggregate function for a group."""
        if func_name == 'COUNT':
            if args == ['*'] or args == ['*']:
                return len(df)
            else:
                col = self._find_column(df, args[0])
                return df[col].notna().sum()
        elif func_name == 'SUM':
            col = self._find_column(df, args[0])
            values = pd.to_numeric(df[col], errors='coerce')
            return values.sum()
        elif func_name == 'MIN':
            col = self._find_column(df, args[0])
            values = pd.to_numeric(df[col], errors='coerce')
            if values.notna().any():
                return values.min()
            return None
        elif func_name == 'MAX':
            col = self._find_column(df, args[0])
            values = pd.to_numeric(df[col], errors='coerce')
            if values.notna().any():
                return values.max()
            return None
        return None

    def _compute_aggregate(self, df: pd.DataFrame, func: Function) -> Any:
        """Compute an aggregate function."""
        func_name = func.get_name().upper()
        args = []
        for arg in func.get_parameters():
            if isinstance(arg, Identifier):
                args.append(self._resolve_column_ref(arg.value))
            elif arg.ttype is Wildcard:
                args.append('*')
            else:
                args.append(arg.value)

        return self._compute_aggregate_for_group(df, func_name, args)

    def _evaluate_having(self, row_data: Dict, having_expr: Any) -> bool:
        """Evaluate a HAVING expression for a group."""
        # Parse the HAVING expression
        tokens = [t for t in having_expr.tokens if not t.is_whitespace]

        result = self._evaluate_having_expr(row_data, tokens)
        return result

    def _evaluate_having_expr(self, row_data: Dict, tokens: List) -> bool:
        """Evaluate a HAVING expression recursively."""
        if len(tokens) == 0:
            return True

        # Handle parentheses
        if isinstance(tokens[0], Parenthesis):
            inner_tokens = [t for t in tokens[0].tokens if not t.is_whitespace]
            return self._evaluate_having_expr(row_data, inner_tokens)

        # Handle NOT
        if self._is_keyword(tokens[0], 'NOT'):
            return not self._evaluate_having_expr(row_data, tokens[1:])

        # Handle comparison
        if len(tokens) >= 3:
            left_val = self._get_having_operand_value(row_data, tokens[0])
            op = tokens[1].value
            right_val = self._get_having_operand_value(row_data, tokens[2])

            if op == '=':
                return left_val == right_val
            elif op == '!=':
                return left_val != right_val
            elif op == '<':
                return float(left_val) < float(right_val)
            elif op == '<=':
                return float(left_val) <= float(right_val)
            elif op == '>':
                return float(left_val) > float(right_val)
            elif op == '>=':
                return float(left_val) >= float(right_val)

        # Handle AND/OR
        if len(tokens) >= 3:
            if self._is_keyword(tokens[1], 'AND'):
                left = self._evaluate_having_expr(row_data, [tokens[0]])
                right = self._evaluate_having_expr(row_data, tokens[2:])
                return left and right
            elif self._is_keyword(tokens[1], 'OR'):
                left = self._evaluate_having_expr(row_data, [tokens[0]])
                right = self._evaluate_having_expr(row_data, tokens[2:])
                return left or right

        return True

    def _get_having_operand_value(self, row_data: Dict, token) -> Any:
        """Get the value of an operand in a HAVING expression."""
        if isinstance(token, Function):
            func_name = token.get_name().upper()
            args = []
            for arg in token.get_parameters():
                if isinstance(arg, Identifier):
                    args.append(arg.value)
                elif arg.ttype is Wildcard:
                    args.append('*')
                else:
                    args.append(arg.value)
            alias = f"{func_name}({','.join(str(a) for a in args)})"
            return row_data.get(alias, 0)
        elif isinstance(token, Identifier):
            alias = token.get_alias() or token.value
            return row_data.get(alias, row_data.get(token.value, token.value))
        elif token.ttype in (sqlparse.tokens.Number.Integer, sqlparse.tokens.Number.Float):
            return float(token.value)
        elif token.ttype is sqlparse.tokens.String.Symbol:
            return token.value.strip("'\"")
        return token.value

    def _project(self, df: pd.DataFrame, select_items: List) -> pd.DataFrame:
        """Project columns from DataFrame."""
        result_data = {}
        column_order = []

        for item in select_items:
            if item[0] == 'wildcard':
                for col in df.columns:
                    # Remove table prefix for display
                    display_col = col.split('.')[-1] if '.' in col else col
                    if display_col not in result_data:
                        result_data[display_col] = df[col]
                        column_order.append(display_col)
            elif item[0] == 'column':
                col_ref = item[1]
                alias = item[2]
                resolved_col = self._find_column(df, col_ref)
                result_data[alias] = df[resolved_col]
                column_order.append(alias)

        return pd.DataFrame(result_data)[column_order]

    def _apply_order_by(self, df: pd.DataFrame, order_items: List[Tuple[str, str]]) -> pd.DataFrame:
        """Apply ORDER BY to DataFrame."""
        for col, direction in reversed(order_items):
            resolved_col = self._find_column(df, col)
            try:
                # Try numeric sort
                numeric_values = pd.to_numeric(df[resolved_col], errors='coerce')
                if numeric_values.notna().all():
                    df = df.sort_values(by=resolved_col, ascending=(direction == 'ASC'), kind='mergesort')
                else:
                    # String sort
                    df = df.sort_values(by=resolved_col, ascending=(direction == 'ASC'), kind='mergesort')
            except (ValueError, KeyError):
                # Fall back to string sort
                df = df.sort_values(by=resolved_col, ascending=(direction == 'ASC'), kind='mergesort')

        return df.reset_index(drop=True)


def format_markdown_table(df: pd.DataFrame) -> str:
    """Format a DataFrame as a markdown table."""
    if len(df) == 0:
        # Empty result - just show headers
        headers = list(df.columns)
        line = '|' + '|'.join(headers) + '|'
        separator = '|' + '|'.join(['---' for _ in headers]) + '|'
        return line + '\n' + separator

    # Replace NaN with NULL
    df = df.fillna('NULL')

    headers = list(df.columns)
    rows = []

    # Header row
    header_row = '|' + '|'.join(str(h) for h in headers) + '|'
    rows.append(header_row)

    # Separator row
    separator = '|' + '|'.join(['---' for _ in headers]) + '|'
    rows.append(separator)

    # Data rows
    for _, row in df.iterrows():
        row_str = '|' + '|'.join(str(v) if v != '' else 'NULL' for v in row) + '|'
        rows.append(row_str)

    return '\n'.join(rows)


def format_csv(df: pd.DataFrame) -> str:
    """Format a DataFrame as CSV."""
    # Replace NaN with empty string for CSV output
    df = df.fillna('')
    return df.to_csv(index=False)


def main():
    parser = argparse.ArgumentParser(description='Run SQL queries on CSV files')
    parser.add_argument('--data', required=True, help='Directory containing CSV files')
    parser.add_argument('--sql', required=True, help='SQL query string or path to SQL file')
    parser.add_argument('--out', help='Path to output CSV file (optional)')

    args = parser.parse_args()

    # Load CSV files
    tables = load_csv_files(args.data)

    if not tables:
        print("No valid CSV files found in the specified directory.", file=sys.stderr)
        sys.exit(1)

    # Get SQL query
    if os.path.isfile(args.sql):
        with open(args.sql, 'r') as f:
            query = f.read()
    else:
        query = args.sql

    # Execute query
    try:
        executor = SQLExecutor(tables)
        result = executor.execute(query)

        # Print as markdown table
        print(format_markdown_table(result))

        # Save to file if specified
        if args.out:
            result.to_csv(args.out, index=False)

    except Exception as e:
        print(f"Error executing query: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

